SELECT (CASE WHEN SUM(A.ALL_CNT) = 0 AND SUM(A.LANG_CNT) = 0 THEN 0 /* NEW INSERT */ WHEN SUM(A.ALL_CNT) > 0 AND SUM(A.LANG_CNT) > 0 THEN 1 /* UPDATE */ WHEN SUM(A.ALL_CNT) > 0 OR SUM(A.LANG_CNT) > 0 THEN 2 /* SELECT INSERT */ ELSE 3 END) CNT FROM ( SELECT COUNT(CODE_TYPE) AS ALL_CNT , 0 AS LANG_CNT FROM STOCCODH WHERE GATE_CD = #{ses.gateCd} AND CODE_TYPE = #{CODE_TYPE}
UNION ALL
SELECT 0 AS ALL_CNT , COUNT(CODE_TYPE) AS LANG_CNT FROM STOCCODH WHERE GATE_CD = #{ses.gateCd} AND CODE_TYPE = #{CODE_TYPE} AND LANG_CD = #{LANG_CD} ) A

